var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`신은 인간을 사랑했다.`,JPN:`神は人間を愛した。`,ENG:`God loved humans.`,TWN:`神曾經愛過人類。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`그렇게 신과 인간 사이에 자손이 태어났다.`,JPN:`そうして神と人間の間に子が生まれた。`,ENG:`And thus, a newborn child emerged between God and a human.`,TWN:`就這樣，神與人之間生出後裔。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`신은 그의 자손에게 많은 걸 베풀고 싶었다.`,JPN:`神は自らの子孫に与えられる限りの恩恵を与えたかった。`,ENG:`God wanted to give her child everything.`,TWN:`神想把一切都給他的後裔。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`narration`,speaker:null,text:{KOREA:`그래서 인간들이 자신을 섬기는 것처럼……`,JPN:`それで人間が神に仕えるのと同じように……`,ENG:`Just as humans worshiped her...`,TWN:`於是像人類侍奉自己一樣……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`narration`,speaker:null,text:{KOREA:`아이에게 권능을 주고, 무녀로 섬겼다.`,JPN:`子に権能を与え、巫女として仕えさせた。`,ENG:`She empowered her child, and appointed her child as a priestess.`,TWN:`給予後裔權能做巫女侍奉神。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`GOD_NPC_NANAHARA2_NULL`,text:{KOREA:`이걸로, 여덟 머리 중 일곱을 베었도다.`,JPN:`これで、八つの頭のうち七つを切り取った。`,ENG:`Seven severed. Only one left, thou.`,TWN:`已經斬掉八顆中的七顆，`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`GOD_NPC_NANAHARA2_NULL`,text:{KOREA:`하지만 너의 독기는 여전히 이승을 허물고 있으니…… 이대로는 세상이 무너지고 말리라.`,JPN:`だが、お主の毒気はいまだ現世を侵し続けている……このままでは世界は崩壊してしまうであろう。`,ENG:`Yet, thy venom still lingers in this world... collapsed shall it be if left unchecked.`,TWN:`但你的毒氣依舊在摧毀現世……再這樣下去，世界會毀滅的。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GOD_NPC_NANAHARA2_NULL`,text:{KOREA:`그러니, 네 마지막 머리를 베어야겠구나. 역신 오로치여.`,JPN:`それゆえ、お主の最後の頭を切り取らねばならぬ。疫病神オロチよ。`,ENG:`Thus, I shall sever thy last head as well, Orochi the Plague God.`,TWN:`因此，必須斬掉你最後一顆頭，瘟神大蛇。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`이 몸은 죽지 않는다. 망자를 다스리는 네놈이라면 잘 알고 있을 텐데?`,JPN:`我は死なん。亡者を治める貴様ならよく知っているはずだ。`,ENG:`I am immortal. You, the ruler of death, should know this, no?`,TWN:`這副軀體是不會死的，管理死人的你應該很清楚吧？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`GOD_NPC_NANAHARA2_NULL`,text:{KOREA:`네 머리들을 베어 봉한다면, 다시 쉽게 인간들을 해칠 순 없겠지.`,JPN:`頭を切り封印すれば、人間を容易く害することはできなくなる。`,ENG:`With thy heads sealed, thou shalt not easily cast doom on man.`,TWN:`等我把你的頭斬下，再將你封印起來，你便無法再危害人類。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`나는……!`,JPN:`我は……！`,ENG:`I...!`,TWN:`我……！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`……인간을 믿었다.`,JPN:`……人間を信じた。`,ENG:`...Trusted them.`,TWN:`……曾經那麼相信人類，`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`하지만 그것들은……`,JPN:`しかし、あやつらは……`,ENG:`But those vile creatures...`,TWN:`他們卻……`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`내가…… 가장 소중히 여기는 분을 죽였어.`,JPN:`我が……もっとも大切にしていた人間を殺した。`,ENG:`They... They slaughtered my beloved.`,TWN:`殺死……我的摯愛。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`그 힘을 빼앗아, 영생을 얻겠다는 이유만으로!`,JPN:`その力を奪い、永生を得たいという理由だけで！`,ENG:`All because they wanted to take her powers and gain eternal life!`,TWN:`只因為他們相信，奪取她的力量可以得到永生！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`GOD_NPC_NANAHARA2_NULL`,text:{KOREA:`알고 있다네.`,JPN:`わかっている。`,ENG:`So I am aware.`,TWN:`我知道。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GOD_NPC_NANAHARA2_NULL`,text:{KOREA:`우리 같은 존재는 인간처럼 한 번 품은 감정을 망각하지 못하지.`,JPN:`我らのような存在は人間のように一度胸に抱いた感情を忘却できぬ。`,ENG:`Being who we are, we do not forget feelings once embraced, unlike humans.`,TWN:`像我們這類的存在，一旦投入感情便無法遺忘。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};